compliant:
using (var aes = new AesCryptoServiceProvider())
{
    aes.Mode = CipherMode.CBC; // Compliant - secure mode
    aes.Padding = PaddingMode.PKCS7; // Compliant - secure padding
}

using (var aes = new AesManaged())
{
    aes.KeySize = 256; // Compliant - strong key
    aes.Mode = CipherMode.GCM; // Compliant - authenticated encryption
}
